import (
	context "context"
	fern "github.com/oauth-client-credentials-reference/fern"
	fernclient "github.com/oauth-client-credentials-reference/fern/client"
	option "github.com/oauth-client-credentials-reference/fern/option"
)

client := fernclient.NewClient(
	option.WithToken(
		"<YOUR_AUTH_TOKEN>",
	),
)
response, err := client.Auth.Gettoken(
	context.TODO(),
	&fern.GetTokenRequest{
		ClientID:     "client_id",
		ClientSecret: "client_secret",
	},
)
